#include <cuda.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <cuda_bf16.h>
#include <math_constants.h>

#include <torch/extension.h>
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>

#include "kernel.h"

// Constants
constexpr int HEAD_SIZE = 128;
constexpr int NUM_Q_HEADS = 4;
constexpr int NUM_K_HEADS = 4;
constexpr int NUM_V_HEADS = 8;
constexpr int NUM_THREADS = 1024; // Optimized for A800
constexpr int TILES_K = 8; // 128 / 16 = 8 chunks of K per thread for compute
constexpr int THREADS_PER_V = NUM_THREADS / HEAD_SIZE; // 1024 / 128 = 8 threads per V

__device__ __forceinline__ float softplus_device(float x) {
    return log1pf(expf(x));
}

__device__ __forceinline__ float sigmoid_device(float x) {
    return 1.0f / (1.0f + expf(-x));
}

__global__ void gdn_decode_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const float* __restrict__ state,
    const float* __restrict__ A_log,
    const __nv_bfloat16* __restrict__ a,
    const float* __restrict__ dt_bias,
    const __nv_bfloat16* __restrict__ b,
    const float scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ new_state,
    int batch_size
) {
    // Grid: [batch_size * num_v_heads]
    // Block: [NUM_THREADS]
    int bid = blockIdx.x;
    int tid = threadIdx.x;

    int batch_idx = bid / NUM_V_HEADS;
    int head_idx = bid % NUM_V_HEADS;

    // Map q/k heads to v heads (GVA mode: 4 q/k heads -> 8 v heads)
    // q[0] -> v[0, 1], q[1] -> v[2, 3], etc.
    int q_head_idx = head_idx / 2;
    int k_head_idx = head_idx / 2;

    // Pointers for this batch/head
    // q: [B, 1, 4, 128] -> stride 128
    const __nv_bfloat16* q_ptr = q + (batch_idx * NUM_Q_HEADS + q_head_idx) * HEAD_SIZE;
    const __nv_bfloat16* k_ptr = k + (batch_idx * NUM_K_HEADS + k_head_idx) * HEAD_SIZE;
    const __nv_bfloat16* v_ptr = v + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE;

    // state: [B, 8, 128, 128] -> stride 128*128
    const float* state_ptr = state + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE * HEAD_SIZE;
    float* new_state_ptr = new_state + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE * HEAD_SIZE;

    // Scalars
    float A_log_val = A_log[head_idx];
    float dt_bias_val = dt_bias[head_idx];
    float a_val = __bfloat162float(a[batch_idx * NUM_V_HEADS + head_idx]);
    float b_val = __bfloat162float(b[batch_idx * NUM_V_HEADS + head_idx]);

    // Compute g and beta
    float x = a_val + dt_bias_val;
    float g = expf(-expf(A_log_val) * softplus_device(x));
    float beta = sigmoid_device(b_val);

    // Shared Memory for State [K, V] (Transposed from [V, K])
    // 128 * 128 * 4 bytes = 64KB
    extern __shared__ float shared_mem[];
    float* state_sm = shared_mem; // [K, V]

    // Load State into Shared Memory (Transposed)
    // Global: [V, K] -> Shared: [K, V]
    // We use 16 passes to load the 128x128 matrix with 1024 threads
    // Each pass loads 8 rows of V (8 * 128 = 1024 elements)
    for (int pass = 0; pass < 16; ++pass) {
        int v_start = pass * 8;
        int v = v_start + (tid / 128); // 0..7
        int k = tid % 128;

        // Global index: v * 128 + k
        // Shared index: k * 128 + v
        if (v < HEAD_SIZE) {
            state_sm[k * HEAD_SIZE + v] = state_ptr[v * HEAD_SIZE + k];
        }
    }
    __syncthreads();

    // Compute u = k^T @ state_sm (Vector [V])
    // u[v] = sum(k[k] * state_sm[k, v])
    // We use 8 threads per V to compute the dot product over K
    // Each thread handles 16 elements of K
    float u[HEAD_SIZE] __attribute__((aligned(256)));
    float u_partial[HEAD_SIZE] __attribute__((aligned(256)));

    // Initialize u_partial
    int v_idx = tid / THREADS_PER_V; // 0..127
    int k_chunk = tid % THREADS_PER_V; // 0..7
    int k_start = k_chunk * 16;

    float sum = 0.0f;
    for (int j = 0; j < 16; ++j) {
        int k_idx = k_start + j;
        sum += __bfloat162float(k_ptr[k_idx]) * state_sm[k_idx * HEAD_SIZE + v_idx];
    }
    u_partial[v_idx] = sum;
    __syncthreads();

    // Reduce u_partial to u (8 threads per v)
    // Thread 0 of the 8 computes the final sum
    if (tid % THREADS_PER_V == 0) {
        float s = 0.0f;
        for (int i = 0; i < THREADS_PER_V; ++i) {
            s += u_partial[v_idx];
            // Note: u_partial is indexed by v_idx, but we need to sum across the 8 threads
            // The 8 threads for v_idx are at tid = v_idx*8, v_idx*8+1, ...
            // We need to access u_partial for the current v_idx from all 8 threads
            // Since u_partial is written by all threads, we need a reduction.
            // Simpler: Just sum u_partial[v_idx] from all 8 threads.
            // But u_partial is stored per thread.
            // Let's fix the reduction logic.
        }
        // Correct reduction:
        // Thread `tid` writes to `u_partial[tid]`.
        // We want `u[v] = sum_{i=0..7} u_partial[v*8 + i]`.
        // Thread `v*8` does the sum.
        if (tid % THREADS_PER_V == 0) {
            float s = 0.0f;
            for (int i = 0; i < THREADS_PER_V; ++i) {
                s += u_partial[v_idx * THREADS_PER_V + i];
            }
            u[v_idx] = s;
        }
    }
    // Wait for reduction
    // Actually, to avoid complex sync, let's just use the first thread to sum.
    // But u_partial is in registers. We need shared memory for reduction if we want to be safe, 
    // or just use the fact that 8 threads are in a warp.
    // Let's use a simpler approach: Store u_partial in shared memory then reduce.
    // Given the constraints, let's just use a small shared array for u reduction.
    // Re-declare u_sm in shared mem? No, we used all 64KB for state.
    // We can reuse state_sm after load? No, we need state_sm for update.
    // We can use registers for u since V=128 fits in registers? 128 floats = 512 bytes.
    // 1024 threads * 512 bytes = 512KB registers. Too much.
    // So we must use shared memory for u.
    // But we filled shared memory with state.
    // Solution: Compute u in place or use a subset of shared memory.
    // We can reduce the state tile size? No, 128x128 is fixed.
    // We can compute u and store it in registers if we process V in chunks.
    // Let's process V in chunks of 16.
    // This complicates the code significantly.
    // Alternative: Use 128 threads per block.
    // 128 threads * 128x128 matrix = 16384 / 128 = 128 elements per thread.
    // 128 floats = 512 bytes. Too many registers.
    // Okay, let's use the 1024 threads but use a smaller shared memory for u.
    // We can't easily overlap state and u.
    // Let's assume we can use registers for `u` if we process `v` in a loop.
    // Loop `v` 0..127.
    // Inside loop, compute `u[v]`.
    // This requires loading `state_sm` column `v` multiple times? No, `state_sm` is in SM.
    // So we can just read `state_sm[k, v]` for all k.
    // Since we have 1024 threads, we can assign 8 threads per `v`.
    // We can compute `u[v]` and store it in a shared array `u_sm[128]`.
    // We need 128 * 4 = 512 bytes for `u_sm`.
    // We can steal 512 bytes from `state_sm`? No, 64KB is tight.
    // Actually, 128x128 floats = 64KB.
    // We can use the last 512 bytes of shared memory for `u_sm`.
    // But `state_sm` is 64KB.
    // A800 Shared Memory is 96KB or 192KB.
    // Let's assume 96KB. 64KB for state + 1KB for u is fine.
    // We need to declare `shared_mem` larger.
    // 64KB + 1KB = 65KB.
    // Let's use 70KB shared memory.
}

// Redefining kernel with proper shared memory sizing
__global__ void gdn_decode_kernel_optimized(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const float* __restrict__ state,
    const float* __restrict__ A_log,
    const __nv_bfloat16* __restrict__ a,
    const float* __restrict__ dt_bias,
    const __nv_bfloat16* __restrict__ b,
    const float scale,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ new_state,
    int batch_size
) {
    int bid = blockIdx.x;
    int tid = threadIdx.x;

    int batch_idx = bid / NUM_V_HEADS;
    int head_idx = bid % NUM_V_HEADS;

    int q_head_idx = head_idx / 2;
    int k_head_idx = head_idx / 2;

    const __nv_bfloat16* q_ptr = q + (batch_idx * NUM_Q_HEADS + q_head_idx) * HEAD_SIZE;
    const __nv_bfloat16* k_ptr = k + (batch_idx * NUM_K_HEADS + k_head_idx) * HEAD_SIZE;
    const __nv_bfloat16* v_ptr = v + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE;

    const float* state_ptr = state + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE * HEAD_SIZE;
    float* new_state_ptr = new_state + (batch_idx * NUM_V_HEADS + head_idx) * HEAD_SIZE * HEAD_SIZE;

    float A_log_val = A_log[head_idx];
    float dt_bias_val = dt_bias[head_idx];
    float a_val = __bfloat162float(a[batch_idx * NUM_V_HEADS + head_idx]);
    float b_val = __bfloat162float(b[batch_idx * NUM_V_HEADS + head_idx]);

    float x = a_val + dt_bias_val;
    float g = expf(-expf(A_log_val) * softplus_device(x));
    float beta = sigmoid_device(b_val);

    // Shared Memory: 128x128 floats (64KB) + 128 floats for u (0.5KB) + 128 floats for out (0.5KB)
    // Total ~65KB. Fits in 96KB SM.
    extern __shared__ float shared_mem[];
    float* state_sm = shared_mem; // [K, V]
    float* u_sm = state_sm + HEAD_SIZE * HEAD_SIZE;
    float* out_sm = u_sm + HEAD_SIZE;

    // Load State into Shared Memory (Transposed)
    for (int pass = 0; pass < 16; ++pass) {
        int v_start = pass * 8;
        int v = v_start + (tid / 128);
        int k = tid % 128;
        if (v < HEAD_SIZE) {
            state_sm[k * HEAD_SIZE + v] = state_ptr[v * HEAD_SIZE + k];
        }
    }
    __syncthreads();

    // Compute u = k^T @ state_sm
    // 8 threads per V
    int v_idx = tid / THREADS_PER_V;
    int k_chunk = tid % THREADS_PER_V;
    int k_start = k_chunk * 16;

    float sum = 0.0f;
    for (int j = 0; j < 16; ++j) {
        int k_idx = k_start + j;
        sum += __bfloat162float(k_ptr[k_idx]) * state_sm[k_idx * HEAD_SIZE + v_idx];
    }
    u_sm[tid] = sum;
    __syncthreads();

    // Reduce u_sm to u_final (stored in u_sm[v_idx])
    if (tid % THREADS_PER_V == 0) {
        float s = 0.0f;
        for (int i = 0; i < THREADS_PER_V; ++i) {
            s += u_sm[v_idx * THREADS_PER_V + i];
        }
        u_sm[v_idx] = s;
    }
    __syncthreads();

    // Compute v_new and delta_v
    // v_new = beta * v + (1 - beta) * u
    // delta_v = v_new - u = beta * (v - u)
    float beta_val = beta;
    float one_minus_beta = 1.0f - beta;

    // Each thread computes delta_v for its v_idx
    float delta_v = 0.0f;
    if (tid < HEAD_SIZE) {
        float u_val = u_sm[tid];
        float v_val = __bfloat162float(v_ptr[tid]);
        delta_v = beta_val * (v_val - u_val);
        u_sm[tid] = delta_v; // Reuse u_sm for delta_v
    }
    __syncthreads();

    // Update state_sm: s_new = g * s_old + k * delta_v^T
    // s_new[k, v] = g * s_old[k, v] + k[k] * delta_v[v]
    // We can process this in 16 passes again to ensure coalesced writes back to global
    // But we need to compute it first.
    // We have 1024 threads, 16384 elements. 16 elements per thread.
    // Thread `tid`:
    // v = tid / 8
    // k_base = (tid % 8) * 16
    // Loop j 0..15: k = k_base + j

    // We can compute and store in registers, then write back.
    // But we need to write back to Global [V, K] which is transposed relative to SM [K, V].
    // So we need to write back in 16 passes (rows of V).

    // Compute delta_v for all v (already in u_sm)
    // Now update state_sm
    // Since we need to write back to global in V-major order, let's do the update in passes.

    for (int pass = 0; pass < 16; ++pass) {
        int v_start = pass * 8;
        int v = v_start + (tid / 128);
        int k = tid % 128;

        if (v < HEAD_SIZE) {
            float s_old = state_sm[k * HEAD_SIZE + v];
            float k_val = __bfloat162float(k_ptr[k]);
            float dv_val = u_sm[v]; // delta_v
            float s_new = g * s_old + k_val * dv_val;

            // Write to new_state [V, K]
            new_state_ptr[v * HEAD_SIZE + k] = s_new;
        }
    }
    __syncthreads();

    // Compute output = scale * q^T @ state_new
    // We need state_new in [K, V] for matmul.
    // We just wrote it to Global [V, K].
    // We can read it back or compute it on the fly.
    // Reading back is expensive.
    // We can compute `out` during the update pass?
    // out[v] = sum(q[k] * state_new[k, v])
    // state_new[k, v] = g * s_old[k, v] + k[k] * dv[v]
    // out[v] = sum(q[k] * (g * s_old[k, v] + k[k] * dv[v]))
    //        = g * sum(q[k] * s_old[k, v]) + dv[v] * sum(q[k] * k[k])
    // This avoids writing state_new to global before reading it!
    // We can compute `out` directly from `state_sm` (which is `s_old`) and `delta_v`.
    // `out[v] = g * (q^T @ s_old[:, v]) + delta_v[v] * (q^T @ k)`
    // `q^T @ k` is a scalar (dot product of q and k).
    // `q^T @ s_old[:, v]` is a matvec.

    // Compute dot_qk = q . k
    float dot_qk = 0.0f;
    int k_chunk_out = tid % THREADS_PER_V;
    int k_start_out = k_chunk_out * 16;
    float sum_qk = 0.0f;
    for (int j = 0; j < 16; ++j) {
        int k_idx = k_start_out + j;
        sum_qk += __bfloat162float(q_ptr[k_idx]) * __bfloat162float(k_ptr[k_idx]);
    }
    // Reduce dot_qk
    // We can use the same reduction pattern as u
    out_sm[tid] = sum_qk;
    __syncthreads();
    if (tid % THREADS_PER_V == 0) {
        float s = 0.0f;
        for (int i = 0; i < THREADS_PER_V; ++i) {
            s += out_sm[i]; // Since tid=0..7 for v=0
        }
        // Wait, out_sm is indexed by tid.
        // We want sum over all threads.
        // Let's just use thread 0 to sum all.
        if (tid == 0) {
            for (int i = 0; i < NUM_THREADS; ++i) {
                s += out_sm[i];
            }
            out_sm[0] = s;
        }
    }
    __syncthreads();
    float dot_qk_final = out_sm[0];

    // Compute out_vec[v] = g * (q^T @ s_old[:, v]) + delta_v[v] * dot_qk
    // We need q^T @ s_old[:, v] for each v.
    // We can compute this in the same pattern as u.
    // Reuse out_sm array to store partial sums for q^T @ s_old.

    // Reset out_sm for partial sums
    int v_idx_out = tid / THREADS_PER_V;
    int k_chunk_out_2 = tid % THREADS_PER_V;
    int k_start_out_2 = k_chunk_out_2 * 16;

    float sum_q_state = 0.0f;
    for (int j = 0; j < 16; ++j) {
        int k_idx = k_start_out_2 + j;
        sum_q_state += __bfloat162float(q_ptr[k_idx]) * state_sm[k_idx * HEAD_SIZE + v_idx_out];
    }
    out_sm[tid] = sum_q_state;
    __syncthreads();

    // Reduce and compute final output
    if (tid % THREADS_PER_V == 0) {
        float s = 0.0f;
        for (int i = 0; i < THREADS_PER_V; ++i) {
            s += out_sm[v_idx_out * THREADS_PER_V + i];
        }
        float q_state = s;
        float dv = u_sm[v_idx_out];
        float out_val = scale * (g * q_state + dv * dot_qk_final);
        out_sm[v_idx_out] = out_val;
    }
    __syncthreads();

    // Write output to global
    // output: [B, 1, 8, 128] -> [B, 8, 128]
    if (tid < HEAD_SIZE) {
        output[batch_idx * NUM_V_HEADS * HEAD_SIZE + head_idx * HEAD_SIZE + tid] = __float2bfloat16(out_sm[tid]);
    }
}

void gdn_decode_qk4_v8_d128_k_last(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    float scale,
    torch::Tensor output,
    torch::Tensor new_state
) {
    int batch_size = q.size(0);
    int num_heads = NUM_V_HEADS;

    // Shared memory size: 64KB (state) + 0.5KB (u) + 0.5KB (out) = 65KB
    size_t shared_mem_size = (HEAD_SIZE * HEAD_SIZE + HEAD_SIZE + HEAD_SIZE) * sizeof(float);

    gdn_decode_kernel_optimized<<<batch_size * num_heads, NUM_THREADS, shared_mem_size>>>(
        q.data_ptr<__nv_bfloat16>(),
        k.data_ptr<__nv_bfloat16>(),
        v.data_ptr<__nv_bfloat16>(),
        state.data_ptr<float>(),
        A_log.data_ptr<float>(),
        a.data_ptr<__nv_bfloat16>(),
        dt_bias.data_ptr<float>(),
        b.data_ptr<__nv_bfloat16>(),
        scale,
        output.data_ptr<__nv_bfloat16>(),
        new_state.data_ptr<float>(),
        batch_size
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <ATen/ATen.h>
#include "kernel.h"

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &gdn_decode_qk4_v8_d128_k_last, "GDN Decode Kernel");
}

// Wrapper function to handle tensor validation and launch
void run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    float scale,
    torch::Tensor output,
    torch::Tensor new_state
) {
    // Validate device
    TORCH_CHECK(q.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(k.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(v.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(state.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(A_log.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(a.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(dt_bias.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(b.is_cuda(), "Input tensors must be on CUDA device");
    TORCH_CHECK(output.is_cuda(), "Output tensors must be on CUDA device");
    TORCH_CHECK(new_state.is_cuda(), "Output tensors must be on CUDA device");

    // Validate dtypes
    TORCH_CHECK(q.dtype() == torch::kBFloat16, "q must be bfloat16");
    TORCH_CHECK(k.dtype() == torch::kBFloat16, "k must be bfloat16");
    TORCH_CHECK(v.dtype() == torch::kBFloat16, "v must be bfloat16");
    TORCH_CHECK(state.dtype() == torch::kFloat32, "state must be float32");
    TORCH_CHECK(A_log.dtype() == torch::kFloat32, "A_log must be float32");
    TORCH_CHECK(a.dtype() == torch::kBFloat16, "a must be bfloat16");
    TORCH_CHECK(dt_bias.dtype() == torch::kFloat32, "dt_bias must be float32");
    TORCH_CHECK(b.dtype() == torch::kBFloat16, "b must be bfloat16");
    TORCH_CHECK(output.dtype() == torch::kBFloat16, "output must be bfloat16");
    TORCH_CHECK(new_state.dtype() == torch::kFloat32, "new_state must be float32");

    // Validate shapes
    TORCH_CHECK(q.size(0) == state.size(0), "Batch size mismatch");
    TORCH_CHECK(q.size(1) == 1, "seq_len must be 1");
    TORCH_CHECK(q.size(2) == 4, "num_q_heads must be 4");
    TORCH_CHECK(q.size(3) == 128, "head_size must be 128");
    TORCH_CHECK(k.size(2) == 4, "num_k_heads must be 4");
    TORCH_CHECK(v.size(2) == 8, "num_v_heads must be 8");
    TORCH_CHECK(state.size(1) == 8, "state num_heads must be 8");
    TORCH_CHECK(state.size(2) == 128, "state V dim must be 128");
    TORCH_CHECK(state.size(3) == 128, "state K dim must be 128");

    // Launch kernel
    gdn_decode_qk4_v8_d128_k_last(
        q, k, v, state, A_log, a, dt_bias, b, scale, output, new_state
    );
}
